import{_ as o,o as i,c as l,ag as d}from"./chunks/framework.DTiDeF2Q.js";const p=JSON.parse('{"title":"關於 Dotfiles | Dotfiles (ZH-TW)","titleTemplate":":title","description":"Dotfiles v0.2.495 技術概覽。 相容 macOS、Linux 和 WSL。透過 Dotfiles 管理。","frontmatter":{"title":"關於 Dotfiles | Dotfiles","description":"Dotfiles v0.2.495 技術概覽。 相容 macOS、Linux 和 WSL。透過 Dotfiles 管理。","lang":"zh-TW","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"關於 Dotfiles | Dotfiles 預覽","canonical":"/zh-tw/about/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"關於 Dotfiles","pageType":"docs","schemaType":"WebPage","permalink":"/zh-tw/about/"},"headers":[],"relativePath":"zh-tw/about/index.md","filePath":"zh-tw/about/index.md","lastUpdated":1773010926000}'),a={name:"zh-tw/about/index.md"};function t(c,e,s,h,r,n){return i(),l("div",null,[...e[0]||(e[0]=[d('<h1 id="關於-dotfiles" tabindex="-1">關於 Dotfiles <a class="header-anchor" href="#關於-dotfiles" aria-label="Permalink to &quot;關於 Dotfiles&quot;">​</a></h1><p>Dotfiles v0.2.495 是由 Chezmoi 管理的跨平台 Shell 配置。</p><h2 id="安裝" tabindex="-1">安裝 <a class="header-anchor" href="#安裝" aria-label="Permalink to &quot;安裝&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">bash</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -c</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;$(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -fsSL</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://raw.githubusercontent.com/sebastienrousseau/dotfiles/master/install.sh)&quot;</span></span></code></pre></div><h2 id="驗證" tabindex="-1">驗證 <a class="header-anchor" href="#驗證" aria-label="Permalink to &quot;驗證&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dot</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> doctor</span></span></code></pre></div><h2 id="核心指令" tabindex="-1">核心指令 <a class="header-anchor" href="#核心指令" aria-label="Permalink to &quot;核心指令&quot;">​</a></h2><ul><li><code>dot apply</code> 套用配置變更。</li><li><code>dot update</code> 更新儲存庫並預熱快取。</li><li><code>dot doctor</code> 驗證路徑、工具和 Shell 健康狀態。</li><li><code>dot heal</code> 修復遺失或損壞的狀態。</li><li><code>dot smoke-test</code> 驗證核心工具鏈。</li></ul><h2 id="相關連結" tabindex="-1">相關連結 <a class="header-anchor" href="#相關連結" aria-label="Permalink to &quot;相關連結&quot;">​</a></h2><ul><li><a href="/zh-tw/aliases/">別名</a></li><li><a href="/zh-tw/functions/">函式</a></li><li><a href="/zh-tw/paths/">路徑</a></li></ul><h2 id="核心命令" tabindex="-1">核心命令 <a class="header-anchor" href="#核心命令" aria-label="Permalink to &quot;核心命令&quot;">​</a></h2><p><code>dot</code> CLI 提供 53 個按類別組織的命令。</p><h3 id="核心" tabindex="-1">核心 <a class="header-anchor" href="#核心" aria-label="Permalink to &quot;核心&quot;">​</a></h3><ul><li><code>dot apply</code> — 套用設定變更.</li><li><code>dot sync</code> — 擷取最新儲存庫狀態並套用.</li><li><code>dot update</code> — 更新儲存庫並預熱快取.</li><li><code>dot add</code> — 將新檔案新增至 Chezmoi 來源.</li><li><code>dot diff</code> — 顯示套用前的待處理變更.</li><li><code>dot status</code> — 顯示受管檔案的狀態.</li><li><code>dot remove</code> — 取消管理檔案並刪除來源項目.</li><li><code>dot cd</code> — 在 Chezmoi 來源目錄中開啟 Shell.</li><li><code>dot edit</code> — 在編輯器中開啟受管檔案.</li><li><code>dot clean-cache</code> — 清除暫存快取.</li><li><code>dot prewarm</code> — 預先填充快取以加快 Shell 啟動.</li></ul><h3 id="診斷" tabindex="-1">診斷 <a class="header-anchor" href="#診斷" aria-label="Permalink to &quot;診斷&quot;">​</a></h3><ul><li><code>dot doctor</code> — 驗證路徑、工具和 Shell 狀態.</li><li><code>dot heal</code> — 自動修復遺失或損壞的狀態.</li><li><code>dot health</code> — 執行輕量級健康探測.</li><li><code>dot verify</code> — 根據來源檢查檔案完整性.</li><li><code>dot scorecard</code> — 輸出設定品質評分.</li><li><code>dot snapshot</code> — 擷取當前狀態以供後續比較.</li><li><code>dot smoke-test</code> — 端到端驗證核心工具鏈.</li><li><code>dot chaos</code> — 注入故障以測試自我修復.</li><li><code>dot bundle</code> — 匯出可攜式設定套件.</li><li><code>dot rollback</code> — 回復到先前的快照.</li><li><code>dot drift</code> — 偵測受管檔案的意外變更.</li><li><code>dot history</code> — 顯示 apply/sync 歷史記錄.</li><li><code>dot benchmark</code> — 測量 Shell 啟動時間.</li><li><code>dot perf</code> — 分析 Shell 初始化緩慢問題.</li></ul><h3 id="外觀" tabindex="-1">外觀 <a class="header-anchor" href="#外觀" aria-label="Permalink to &quot;外觀&quot;">​</a></h3><ul><li><code>dot theme</code> — 切換終端機配色方案.</li><li><code>dot wallpaper</code> — 設定桌面桌布（macOS）.</li><li><code>dot fonts</code> — 安裝或更新 Nerd Fonts.</li><li><code>dot tune</code> — 調整介面密度和提示符樣式.</li></ul><h3 id="安全" tabindex="-1">安全 <a class="header-anchor" href="#安全" aria-label="Permalink to &quot;安全&quot;">​</a></h3><ul><li><code>dot backup</code> — 建立加密的設定備份.</li><li><code>dot encrypt-check</code> — 驗證靜態密鑰加密.</li><li><code>dot firewall</code> — 設定主機防火牆規則.</li><li><code>dot telemetry</code> — 控制匿名使用遙測.</li><li><code>dot dns-doh</code> — 啟用 DNS-over-HTTPS.</li><li><code>dot lock-screen</code> — 立即鎖定螢幕.</li><li><code>dot usb-safety</code> — 限制 USB 大容量儲存自動掛載.</li></ul><h3 id="密鑰" tabindex="-1">密鑰 <a class="header-anchor" href="#密鑰" aria-label="Permalink to &quot;密鑰&quot;">​</a></h3><ul><li><code>dot secrets-init</code> — 初始化密鑰後端（age / GPG）.</li><li><code>dot secrets</code> — 列出加密的密鑰項目.</li><li><code>dot secrets-create</code> — 建立新的加密密鑰.</li><li><code>dot ssh-key</code> — 產生或輪換 SSH 金鑰對.</li><li><code>dot ssh-cert</code> — 從 CA 請求 SSH 憑證.</li></ul><h3 id="ai" tabindex="-1">AI <a class="header-anchor" href="#ai" aria-label="Permalink to &quot;AI&quot;">​</a></h3><ul><li><code>dot ai</code> — 開啟互動式 AI 助理工作階段.</li><li><code>dot ai-setup</code> — 設定 AI 供應商的 API 金鑰.</li><li><code>dot ai-query</code> — 向 AI 模型傳送一次性提示.</li><li>AI 工具包裝器: <code>cl</code>, <code>gemini</code>, <code>kiro</code>, <code>sgpt</code>, <code>ollama</code>, <code>opencode</code>, <code>aider</code>.</li></ul><h3 id="工具" tabindex="-1">工具 <a class="header-anchor" href="#工具" aria-label="Permalink to &quot;工具&quot;">​</a></h3><ul><li><code>dot tools</code> — 列出內建的 CLI 替代工具及其狀態.</li><li><code>dot new</code> — 建立新的別名或函數檔案.</li><li><code>dot sandbox</code> — 開啟一次性沙盒 Shell.</li><li><code>dot keys</code> — 顯示目前按鍵繫結.</li><li><code>dot learn</code> — 啟動互動式教學.</li></ul><h3 id="元資訊" tabindex="-1">元資訊 <a class="header-anchor" href="#元資訊" aria-label="Permalink to &quot;元資訊&quot;">​</a></h3><ul><li><code>dot upgrade</code> — 將 Dotfiles 升級到最新版本.</li><li><code>dot packages</code> — 列出 Dotfiles 管理的已安裝套件.</li><li><code>dot version</code> / <code>dot help</code> — 顯示版本或使用資訊</li></ul>',28)])])}const b=o(a,[["render",t]]);export{p as __pageData,b as default};
